example_bad:
trait Processor {
    fn process(&self, data: &str) -> String;
}

struct MyProcessor;

impl Processor for MyProcessor {
    fn process(&self, data: String) -> String { // Error: expected &str, got String
        data.to_uppercase()
    }
}

fixes.code:
impl Processor for MyProcessor {
    fn process(&self, data: &str) -> String {
        data.to_uppercase()
    }
}
